import React from 'react';
import './App.css';

function App() {
  // Burası sizin projenizin ekranda listeleyeceği örnek verilerdir. 
  // İleride burayı kendi verilerinizle doldurabilirsiniz.
  const benimVerilerim = [
    { id: 1, isim: "Futbol Maçı Ödevi", detay: "Spor yöneticisi uygulaması arayüzü" },
    { id: 2, isim: "Veritabanı Projesi", detay: "SQL sorguları ve transactional işlemler" },
    { id: 3, isim: "Bilgisayar Ağları", detay: "UDP Client-Server paketi simülasyonu" }
  ];

  return (
    <div className="App">
      <header className="App-header">
        <h2>Benim React Projem</h2>
      </header>

      {/* GitHub'dan kopyaladığınız ve çalıştırmak istediğiniz asıl döngü alanı */}
      <div className="proje-konteyner">
        {benimVerilerim.map((item) => (
          <div key={item.id} className="kart">
            <div className="kart-icerik">
              <h3>{item.isim}</h3>
              <p>{item.detay}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
